sys_variable_value.value:
(function(outputs, steps, stepResult, assertEqual) {
    var table = 'x_1839224_chroma_0_chromatech_customer_queries'; // actual table name
    var details = [];
    var allPassed = true;

    var fieldSpecs = [
        { name: 'phone', label: 'Phone', type: 'string', size: 10 },
        { name: 'email', label: 'Email', type: 'string', size: 16 },
        { name: 'place', label: 'Place', type: 'reference', reference: 'cmn_location' },
        { name: 'issue_category', label: 'Issue Category', type: 'choice', choices: ['Hardware Issue', 'Firmware Issue'] },
        { name: 'issue_state', label: 'Issue State', type: 'choice', choices: ['New', 'In Progress', 'On Hold', 'Closed'] },
        { name: 'on_hold_reason', label: 'On Hold Reason', type: 'choice', choices: ['Awaiting Caller', 'Awaiting Vendor'] }
    ];

    fieldSpecs.forEach(function(spec) {
        var dict = new GlideRecord('sys_dictionary');
        dict.addQuery('name', table);
        dict.addQuery('element', spec.name);
        dict.query();

        if (dict.next()) {
            var fieldValid = true;
            var logs = "Field [" + spec.label + "]: ";

            // Check Type
            if (dict.internal_type != spec.type) {
                logs += "FAILED type (Expected: " + spec.type + ", Found: " + dict.internal_type + "); ";
                fieldValid = false;
            }

            // Check Size (for strings)
            if (spec.size && dict.max_length != spec.size) {
                logs += "FAILED size (Expected: " + spec.size + ", Found: " + dict.max_length + "); ";
                fieldValid = false;
            }

            // Check Reference
            if (spec.reference && dict.reference != spec.reference) {
                logs += "FAILED reference (Expected: " + spec.reference + ", Found: " + dict.reference + "); ";
                fieldValid = false;
            }

            // Check Choices
            if (spec.choices) {
                var choiceGr = new GlideRecord('sys_choice');
                choiceGr.addQuery('name', table);
                choiceGr.addQuery('element', spec.name);
                choiceGr.addQuery('inactive', false);
                choiceGr.query();
                
                var foundChoices = [];
                while(choiceGr.next()) { foundChoices.push(choiceGr.label.getDisplayValue()); }
                
                spec.choices.forEach(function(c) {
                    if (foundChoices.indexOf(c) === -1) {
                        logs += "MISSING Choice: " + c + "; ";
                        fieldValid = false;
                    }
                });
            }

            if (fieldValid) {
                logs += "PASSED all configuration checks.";
            } else {
                allPassed = false;
            }
            details.push(logs);
        } else {
            details.push("Field [" + spec.label + "]: FAILED - Field not found on table.");
            allPassed = false;
        }
    });

    var finalMessage = details.join('\n');
    if (allPassed) {
        stepResult.setOutputMessage("SUCCESS: All ChromaTech fields validated.\n\n" + finalMessage);
        stepResult.setSuccess();
    } else {
        stepResult.setOutputMessage("FAILURE: Field configuration mismatch.\n\n" + finalMessage);
        stepResult.setFailed();
    }

})(outputs, steps, stepResult, assertEqual);
